// Validates the shop name and builds the public shop lookup URL.
const config = $input.first().json;
const shopName = String(config.shop_name || '').trim();
if (!shopName || shopName === 'ENTER_ETSY_SHOP_NAME') {
  throw new Error('Enter an Etsy shop name in Configuration (EDIT ME).');
}
const listingLimit = Math.min(100, Math.max(1, Math.round(Number(config.listing_limit || 100))));
return [{ json: {
  shop_name: shopName,
  listing_limit: listingLimit,
  lookup_url: `https://api.etsy.com/v3/application/shops?shop_name=${encodeURIComponent(shopName)}`
} }];

// Resolves the lookup result to a numeric shop ID and builds the listings URL.
const response = $input.first().json;
const config = $('Build Etsy shop lookup').first().json;
const shop = Array.isArray(response.results) ? response.results[0] : null;
if (!shop?.shop_id) {
  throw new Error(`Etsy shop not found: ${config.shop_name}`);
}
return [{ json: {
  shop,
  shop_id: String(shop.shop_id),
  listing_limit: config.listing_limit,
  listings_url: `https://api.etsy.com/v3/application/shops/${shop.shop_id}/listings/active?limit=${config.listing_limit}&sort_on=created&sort_order=down&includes=Images`
} }];

// Creates a shop audit and compares the active catalog with the previous production run.
const response = $input.first().json;
const request = $('Build active listings request').first().json;
const shop = request.shop;
const listings = Array.isArray(response.results) ? response.results : [];
const staticData = $getWorkflowStaticData('global');
const previous = staticData.etsyShopAuditSnapshot || {};
const hasPreviousSnapshot = Object.keys(previous).length > 0;
const current = {};
const prices = [];
const taxonomyCounts = {};
let personalizedCount = 0;

const moneyValue = (money) => {
  const amount = Number(money?.amount);
  const divisor = Number(money?.divisor || 100);
  return Number.isFinite(amount) && divisor > 0 ? amount / divisor : null;
};

for (const listing of listings) {
  const id = String(listing.listing_id);
  const price = moneyValue(listing.price);
  if (price !== null) prices.push(price);
  if (listing.is_personalizable) personalizedCount += 1;
  const taxonomy = String(listing.taxonomy_id || '');
  if (taxonomy) taxonomyCounts[taxonomy] = (taxonomyCounts[taxonomy] || 0) + 1;
  current[id] = {
    listing_id: id,
    title: listing.title || '',
    price,
    currency: listing?.price?.currency_code || '',
    quantity: listing.quantity ?? null,
    is_personalizable: Boolean(listing.is_personalizable),
    taxonomy_id: listing.taxonomy_id || null,
    created_timestamp: listing.created_timestamp || null,
    updated_timestamp: listing.updated_timestamp || null,
    url: listing.url || `https://www.etsy.com/listing/${id}`,
    image_url: listing.images?.[0]?.url_570xN || ''
  };
}

const newListings = hasPreviousSnapshot
  ? Object.keys(current).filter((id) => !previous[id]).map((id) => current[id])
  : [];
const removedListings = hasPreviousSnapshot
  ? Object.keys(previous).filter((id) => !current[id]).map((id) => previous[id])
  : [];
staticData.etsyShopAuditSnapshot = current;

prices.sort((a, b) => a - b);
const average = prices.length ? prices.reduce((sum, value) => sum + value, 0) / prices.length : null;
const median = prices.length === 0 ? null : prices.length % 2
  ? prices[(prices.length - 1) / 2]
  : (prices[prices.length / 2 - 1] + prices[prices.length / 2]) / 2;
const topTaxonomies = Object.entries(taxonomyCounts)
  .sort((a, b) => b[1] - a[1]).slice(0, 10)
  .map(([taxonomy_id, occurrences]) => ({ taxonomy_id, occurrences }));

return [{ json: {
  status: hasPreviousSnapshot ? 'comparison_complete' : 'baseline_created',
  checked_at: new Date().toISOString(),
  shop: {
    shop_id: String(shop.shop_id), shop_name: shop.shop_name, title: shop.title || '',
    url: shop.url || '', currency_code: shop.currency_code || '', is_vacation: Boolean(shop.is_vacation),
    listing_active_count_reported_by_etsy: Number(shop.listing_active_count || response.count || 0),
    num_favorers: Number(shop.num_favorers || 0), accepts_custom_requests: Boolean(shop.accepts_custom_requests)
  },
  analyzed_count: listings.length,
  sample_note: `Catalog metrics and change detection use the newest ${listings.length} active listings returned by Etsy. Increase the limit up to 100 if needed.`,
  price_statistics: {
    minimum: prices.length ? Math.min(...prices) : null,
    maximum: prices.length ? Math.max(...prices) : null,
    average: average === null ? null : Math.round(average * 100) / 100,
    median: median === null ? null : Math.round(median * 100) / 100
  },
  personalized_share_percent: listings.length ? Math.round((personalizedCount / listings.length) * 10000) / 100 : 0,
  top_taxonomy_ids: topTaxonomies,
  new_listings: newListings,
  removed_listings: removedListings,
  total_catalog_changes: newListings.length + removedListings.length,
  listings: Object.values(current)
} }];
